### Swift In-Out Parameters

In-out parameters allow a function to modify the value of a variable passed as an argument. The value is copied into the function, modified, and copied back out when the function returns.

**In-Out Syntax:**

```swift
func functionName(_ parameter: inout Type) {
    parameter = newValue
}

func swapValues(_ a: inout Int, _ b: inout Int) {
    let temp = a
    a = b
    b = temp
}

var x = 10
var y = 20
swapValues(&x, &y)
print("x: \(x), y: \(y)")  // x: 20, y: 10
```

**Rules and Limitations:**

| Rule | Description |
|------|-------------|
| Must be `var` | Cannot pass a constant (`let`) |
| Ampersand `&` | Must prefix argument with `&` |
| No default values | In-out parameters cannot have defaults |
| No variadic | In-out cannot be variadic |
| Same variable | Cannot pass the same variable to multiple inout parameters |

```swift
// Practical examples
func increment(_ number: inout Int, by amount: Int = 1) {
    number += amount
}

func updateUser(name: inout String, age: inout Int) {
    if name.isEmpty {
        name = "Anonymous"
    }
    if age < 0 {
        age = 0
    }
}

var score = 50
increment(&score, by: 10)
print("Score: \(score)")  // 60

var userName = ""
var userAge = -5
updateUser(name: &userName, age: &userAge)
print("Name: \(userName), Age: \(userAge)")  // Anonymous, 0
```

> **Key Point:** In-out parameters follow copy-in copy-out semantics. The value is copied before the function call and copied back after. For performance, Swift may use pass-by-reference optimization.

```swift
// Array modification in place
func appendUnique(_ element: Int, to array: inout [Int]) {
    if !array.contains(element) {
        array.append(element)
    }
}

var numbers = [1, 2, 3]
appendUnique(4, to: &numbers)  // [1, 2, 3, 4]
appendUnique(2, to: &numbers)  // [1, 2, 3, 4] (no change)
```

codeExample:
import Foundation

// Swap two values
func swapStrings(_ a: inout String, _ b: inout String) {
    let temp = a
    a = b
    b = temp
}

var firstName = "Alice"
var lastName = "Bob"
swapStrings(&firstName, &lastName)
print("First: \(firstName), Last: \(lastName)")

// Modify array in place
func capitalizeFirstLetter(of strings: inout [String]) {
    for i in strings.indices {
        strings[i] = strings[i].capitalized
    }
}

var words = ["swift", "objective-c", "c++"]
capitalizeFirstLetter(of: &words)
print("Capitalized: \(words)")

// Combine values
func accumulate(_ total: inout Int, _ values: Int...) {
    for value in values {
        total += value
    }
}

var sum = 100
accumulate(&sum, 10, 20, 30)
print("Sum: \(sum)")  // 160
